/* Lookup font entry by Unicode code point */
static const FONT_ENTRY *FontLookup(UINT16 code) {
  INT32 lo = 0, hi = FONT_ENTRY_COUNT - 1;
  while (lo <= hi) {
    INT32 mid = (lo + hi) / 2;
    if (gFontEntries[mid].Code == code) return &gFontEntries[mid];
    if (gFontEntries[mid].Code < code) lo = mid + 1;
    else hi = mid - 1;
  }
  return NULL;
}

